import{_ as e,c as a,o,aj as c}from"./chunks/framework.CLcCQpUA.js";const t="/ComicGUISpider/assets/conf_usage.DaCvN5bM.png",_=JSON.parse('{"title":"🔨 主配置","description":"","frontmatter":{},"headers":[],"relativePath":"config/index.md","filePath":"config/index.md"}'),i={name:"config/index.md"},r=c('<h1 id="🔨-主配置" tabindex="-1">🔨 主配置 <a class="header-anchor" href="#🔨-主配置" aria-label="Permalink to &quot;🔨 主配置&quot;">​</a></h1><p><img src="'+t+'" alt="conf"></p><div class="info custom-block"><p class="custom-block-title">配置文件为初始使用后产生的 <code>conf.yml</code> （<a href="/ComicGUISpider/faq/extra.html#_3-配置系文件路径">📒3-配置系文件路径</a>）</p><p>有关生效时间节点请查阅 <a href="./../faq/extra.html#_2-配置生效相关">📒2-配置生效相关</a></p></div><div class="warning custom-block"><p class="custom-block-title">多行的编辑框输入为 <code>yaml</code> 格式（除了 cookies ），冒号后要加一个⚠️ <code>空格</code> ⚠️</p></div><h2 id="配置项-对应-yml-字段" tabindex="-1">配置项 / 对应 <code>yml</code> 字段 <a class="header-anchor" href="#配置项-对应-yml-字段" aria-label="Permalink to &quot;配置项 / 对应 `yml` 字段&quot;">​</a></h2><h3 id="存储路径-sv-path" tabindex="-1">存储路径 / <code>sv_path</code> <a class="header-anchor" href="#存储路径-sv-path" aria-label="Permalink to &quot;存储路径 / `sv_path`&quot;">​</a></h3><div class="warning custom-block"><p class="custom-block-title">良好的习惯是创建一个空目录，并设于此处</p><p>因为默认值，⚠️ win 没D盘的必须改<br> 同时设置防呆警告，所列情况设置无效：①设在盘符根；②设在 CGS 相关目录内</p></div><p>下载目录<br> 默认值： <code>win: D:\\Comic</code> <code>macOS: ~/Downloads/Comic</code><br> 目录结构里还有个 <code>web</code> 文件夹的情况是因为默认关联 <a href="https://github.com/jasoneri/redViewer" target="_blank" rel="noreferrer"><code>redViewer</code></a> 项目而设的</p><h3 id="日志等级-log-level" tabindex="-1">日志等级 / <code>log_level</code> <a class="header-anchor" href="#日志等级-log-level" aria-label="Permalink to &quot;日志等级 / `log_level`&quot;">​</a></h3><p>后台运行过后会有 log 目录，GUI 与 后台 同级，报错时 GUI 会进行操作指引</p><h3 id="并发数-concurr-num" tabindex="-1">并发数 / <code>concurr_num</code> <a class="header-anchor" href="#并发数-concurr-num" aria-label="Permalink to &quot;并发数 / `concurr_num`&quot;">​</a></h3><p>影响后台下载速度</p><h3 id="去重-isdeduplicate" tabindex="-1">去重 / <code>isDeduplicate</code> <a class="header-anchor" href="#去重-isdeduplicate" aria-label="Permalink to &quot;去重 / `isDeduplicate`&quot;">​</a></h3><p>勾选状态下，预览窗口会有已下载的样式提示<br> 同时下载也会自动过滤已存在的记录</p><div class="info custom-block github-alert"><p class="custom-block-title">当前仅🔞网适用</p><p></p></div><h3 id="增加标识-adduuid" tabindex="-1">增加标识 / <code>addUuid</code> <a class="header-anchor" href="#增加标识-adduuid" aria-label="Permalink to &quot;增加标识 / `addUuid`&quot;">​</a></h3><p>存储时目录最后增加标识，用以处理同一命名的不同作品等（<a href="./../faq/other.html#_1-去重，增加标识相关说明">对应逻辑</a>）</p><h3 id="代理-proxies" tabindex="-1">代理 / <code>proxies</code> <a class="header-anchor" href="#代理-proxies" aria-label="Permalink to &quot;代理 / `proxies`&quot;">​</a></h3><p>翻墙用</p><div class="warning custom-block github-alert"><p class="custom-block-title">⚠️ 已设置 jm 无论用全局还是怎样都只走本地原生ip</p><p></p></div><div class="info custom-block github-alert"><p class="custom-block-title">建议使用代理模式在此配置代理，而非全局代理模式，不然访问图源会吃走大量代理的流量</p><p></p></div><h3 id="映射-custom-map" tabindex="-1">映射 / <code>custom_map</code> <a class="header-anchor" href="#映射-custom-map" aria-label="Permalink to &quot;映射 / `custom_map`&quot;">​</a></h3><p>搜索输入映射<br> 当搜索与预设不满足使用时，先在此加入键值对，重启后在搜索框输入自定义键就会将对应网址结果输出，<code>🎥视频使用指南3</code>有介绍用法</p><ol><li>映射无需理会域名，前提是用在当前网站，只要满足 <code>不用映射时能访问</code> 和 <code>填入的不是无效的url</code>， 程序会内置替换成可用的域名，如非代理下映射的<code>wnacg.com</code>会自动被替换掉</li><li>注意自制的映射有可能超出翻页规则范围，此时可通知开发者进行扩展</li></ol><h3 id="预设-completer" tabindex="-1">预设 / <code>completer</code> <a class="header-anchor" href="#预设-completer" aria-label="Permalink to &quot;预设 / `completer`&quot;">​</a></h3><p>自定义预设<br> 鼠标悬停在输入框会有<code>序号对应网站</code>的提示(其实就是选择框的序号)<br><code>🎥视频使用指南3</code>有介绍用法</p><h3 id="cookies-cookies" tabindex="-1">cookies / <code>cookies</code> <a class="header-anchor" href="#cookies-cookies" aria-label="Permalink to &quot;cookies / `cookies`&quot;">​</a></h3><p>目前选择编辑支持 <code>ehentai</code>, <code>jm</code></p><p><a href="https://jsd.vxo.im/gh/jasoneri/imgur@main/CGS/ehentai_get_cookies_new.gif" target="_blank" rel="noreferrer">🎬获取方法</a> | <a href="https://tool.lu/curl/" target="_blank" rel="noreferrer">🔗动图中的curl转换网站</a><br> 任意网站同理，登录状态下开 F12 控制台然后点首页，筛选出 html/文档 类型请求复制其 curl (POSIX/bash)<br><code>v2.2.6-beta</code> 之后版本支持直接将 curl 文本粘贴到编辑框内，程序已内置转换处理</p><div class="warning custom-block"><p class="custom-block-title">使用 exhentai 时必需设值</p><p>设值后，大量下载导致被服务器对账号实施处理的后果自行负责</p></div><h3 id="剪贴板db-clip-db" tabindex="-1">剪贴板db / <code>clip_db</code> <a class="header-anchor" href="#剪贴板db-clip-db" aria-label="Permalink to &quot;剪贴板db / `clip_db`&quot;">​</a></h3><div class="tip custom-block"><p class="custom-block-title">前提：已阅 <a href="/ComicGUISpider/feat/index.html#_5-读剪贴板"><code>🎸5-读剪贴板</code></a> 功能说明</p></div><p>读取剪贴板功能无法使用时可查看路径是否存在，通过以下查得正确路径后在此更改</p><ol><li>ditto(win): 打开选项 → 数据库路径</li><li>maccy(macOS): <a href="https://github.com/p0deje/Maccy/issues/271" target="_blank" rel="noreferrer">issue 搜索相关得知</a></li></ol><h3 id="读取条数-clip-read-num" tabindex="-1">读取条数 / <code>clip_read_num</code> <a class="header-anchor" href="#读取条数-clip-read-num" aria-label="Permalink to &quot;读取条数 / `clip_read_num`&quot;">​</a></h3><p>读取剪贴板软件条目数量</p><h2 id="其他-yml-字段" tabindex="-1">其他 <code>yml</code> 字段 <a class="header-anchor" href="#其他-yml-字段" aria-label="Permalink to &quot;其他 `yml` 字段&quot;">​</a></h2><div class="info custom-block"><p class="custom-block-title">此类字段没提供配置窗口便捷修改（或以后支持），不设时使用默认值</p></div><h3 id="img-sv-type" tabindex="-1"><code>img_sv_type</code> <a class="header-anchor" href="#img-sv-type" aria-label="Permalink to &quot;`img_sv_type`&quot;">​</a></h3><p>默认值： <code>jpg</code><br> 图片文件命名后缀</p><h3 id="rv-script" tabindex="-1"><code>rv_script</code> <a class="header-anchor" href="#rv-script" aria-label="Permalink to &quot;`rv_script`&quot;">​</a></h3><p>默认值：<br> rV(redViewer) 绑定的启动脚本，用于启动 rV 等</p><h3 id="bg-path" tabindex="-1"><code>bg_path</code> <a class="header-anchor" href="#bg-path" aria-label="Permalink to &quot;`bg_path`&quot;">​</a></h3><p>默认值：<br> 会递归搜索该目录下所有png格式图片，然后随机抽一张设成文本输出框的背景</p>',44),l=[r];function d(s,h,n,p,m,u){return o(),a("div",null,l)}const f=e(i,[["render",d]]);export{_ as __pageData,f as default};
